import{_ as i,o as n,c as o,ag as a}from"./chunks/framework.nZ6LtKJQ.js";const m=JSON.parse('{"title":"Xem bài học","description":"","frontmatter":{},"headers":[],"relativePath":"lessons-guide.md","filePath":"lessons-guide.md","lastUpdated":null}'),h={name:"lessons-guide.md"};function e(c,t,r,s,l,d){return n(),o("div",null,[...t[0]||(t[0]=[a('<h1 id="xem-bai-hoc" tabindex="-1">Xem bài học <a class="header-anchor" href="#xem-bai-hoc" aria-label="Permalink to &quot;Xem bài học&quot;">​</a></h1><p>Bài học trên TunAcademy được giáo viên tạo và gán vào từng lớp học. Học sinh chỉ thấy bài học của những lớp mình tham gia.</p><h2 id="truy-cap-bai-hoc" tabindex="-1">Truy cập bài học <a class="header-anchor" href="#truy-cap-bai-hoc" aria-label="Permalink to &quot;Truy cập bài học&quot;">​</a></h2><p><strong>Cách 1 — Qua Lớp học:</strong></p><ol><li>Vào <strong>Lớp học</strong> → chọn lớp muốn xem</li><li>Nhấn vào tab <strong>Bài học</strong></li><li>Chọn bài học để xem nội dung</li></ol><p><strong>Cách 2 — Qua menu Bài học:</strong></p><ol><li>Nhấn <strong>Bài học</strong> trên sidebar</li><li>Danh sách tất cả bài học từ các lớp đang tham gia</li><li>Lọc theo môn hoặc lớp nếu cần</li></ol><h2 id="giao-dien-xem-bai-hoc" tabindex="-1">Giao diện xem bài học <a class="header-anchor" href="#giao-dien-xem-bai-hoc" aria-label="Permalink to &quot;Giao diện xem bài học&quot;">​</a></h2><p>Mỗi bài học bao gồm:</p><ul><li><strong>Tiêu đề và mô tả</strong> — Tóm tắt nội dung bài</li><li><strong>Nội dung chính</strong> — Văn bản, hình ảnh, video được giáo viên soạn</li><li><strong>Tài liệu đính kèm</strong> — File PDF, slide hoặc tài nguyên bổ sung (nếu có)</li></ul><h2 id="theo-doi-tien-đo" tabindex="-1">Theo dõi tiến độ <a class="header-anchor" href="#theo-doi-tien-đo" aria-label="Permalink to &quot;Theo dõi tiến độ&quot;">​</a></h2><p>Bài học có các trạng thái:</p><table tabindex="0"><thead><tr><th>Trạng thái</th><th>Ý nghĩa</th></tr></thead><tbody><tr><td><strong>Chưa xem</strong></td><td>Bài học mới, chưa mở lần nào</td></tr><tr><td><strong>Đang học</strong></td><td>Đã mở nhưng chưa hoàn thành</td></tr><tr><td><strong>Hoàn thành</strong></td><td>Đã xem xong toàn bộ nội dung</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Sau khi xem xong một bài học, đừng quên kiểm tra phần <strong>Bài tập</strong> của bài đó. Giáo viên thường giao bài tập kèm theo bài học mới.</p></div>',14)])])}const b=i(h,[["render",e]]);export{m as __pageData,b as default};
